    @RequestMapping("/file/upldAtchFileAjax.do")
    public ModelAndView upldAtchFile(HttpServletRequest request, HttpServletResponse res, @RequestParam Map<String, Object> commandMap) throws Exception {
        String viewMsg = "";
        boolean cannumOver = false;
        try {
            // 물리파일 저장
            //EgovFileUploadUtil egovFileUploadUtil = new EgovFileUploadUtil();
            List<EgovFormBasedFileVo> tmpFileList = egovFileUploadUtil.uploadFiles(request, res);
            List<Map<String, Object>> fileList = new ArrayList<Map<String, Object>>();

            String resultCode = "";
            String resultMsg = "";
            Map<String, Object> tmpMap = null;
            EgovFormBasedFileVo fileVO = null;
            for (int i = 0; i < tmpFileList.size(); i++) {
                fileVO = tmpFileList.get(i);
                tmpMap = new HashMap<String, Object>();

                if( "9".equals(fileVO.getResultCode()) ){
                    mv.addObject("cannumCode", "9");
                    mv.addObject("cannumMsg", "첨부파일 갯수를 확인하세요.");
                    cannumOver = true;
                    continue;
                }

                tmpMap.put("fileKey", fileVO.getFileKey());
                tmpMap.put("fieldName", fileVO.getFieldName());
                tmpMap.put("contentType", fileVO.getContentType());
                tmpMap.put("fileName", fileVO.getFileName());
                tmpMap.put("physicalName", fileVO.getPhysicalName());
                tmpMap.put("serverSubPath", fileVO.getServerSubPath());
                tmpMap.put("size", fileVO.getSize());
                tmpMap.put("atchId", fileVO.getAtchId());
                tmpMap.put("resultCode", fileVO.getResultCode());
                tmpMap.put("resultMsg", fileVO.getResultMsg());

                fileList.add(tmpMap);

            }
            mv.addObject("data", fileList);

            if(!cannumOver){
                mv.addObject("cannumCode", "");
                mv.addObject("cannumMsg", "");
            }

        } catch (NullPointerException e) {
            viewMsg = e.getMessage();
            mv.addObject("viewMsg", viewMsg);
        } catch (Exception e) {
            viewMsg = e.getMessage();
            mv.addObject("viewMsg", viewMsg);
        }

        CommonUtil commonUtil = new CommonUtil();
        String urlType = commonUtil.isUrlType(request);

        if ( "json".equals(urlType) ) {
            return success();
        } else {
            return success("sia/cmmn/file/upldAtchfile");
        }

    }
    @RequestMapping("/file/upldAtchFileAjax2.json")
    public ModelAndView upldAtchFileAjax2(HttpServletRequest request, HttpServletResponse res, @RequestBody List<Map<String, Object>> commandMap) throws Exception {
    	String viewMsg = "";
    	boolean cannumOver = false;
    	try {
    		// 물리파일 저장
    		//EgovFileUploadUtil egovFileUploadUtil = new EgovFileUploadUtil();
    		String atchId = "";
    		if(commandMap.size()>0){
    			atchId = (String) commandMap.get(0).get("atchId");
    		}
    		Map<String, Object> atchMap = null;
    		if("".equals(atchId) || atchId == null){
    			atchMap = atchFileService.getAtchId();
    			atchId = atchMap.get("ATCH_ID").toString();
    		}
    		Map<String,Object> param = new HashMap<String,Object>();
    		List<HashMap<String, Object>> fileList = new ArrayList<HashMap<String, Object>>();
    		for(Map<String,Object> map : commandMap){
				param.put("fileName", map.get("originalName"));
				param.put("contentType", map.get("mimeType"));
				param.put("physicalName", map.get("uploadName"));
				param.put("serverSubPath", "");
				param.put("size", map.get("size"));
				param.put("fieldName", "");
				param.put("atchId", atchId);
				param.put("excel",MapUtils.getString(map, "excel","")); //엑셀 데이터 게시판 파일 여부
				fileList.add(atchFileService.insAtchFile(param, request));
    		}
    		mv.addObject("data", fileList);

    	}catch(Exception e){
    		Logger.getLogger(AtchFileController.class).error("파일 업로드 에러");
    	}
    	return success();
