	//첨부파일 불러오기 기능
	function fn_attchDownload(cNo){
		var url = "<c:url value='/file/copyFiles.do'/>";
		data = {"C_NO" : cNo};
		$.ajax({
			url        : url
			, type     : 'post'
			, data     : data
			, async    : true
			, dataType : 'json'
			, success  : function(json) {
				if( json.msg != "" ){
                	alert(json.msg);
                	location.reload();
                } else {
                	alert("첨부파일을 불러오는 중입니다.");
                	location.reload();
                }
			}
