    @Override
    @Transactional(value="txManager")
    public String updateSingoAttachFilesCopy(HashMap<String, Object> paramMap){
		try {
			List<HashMap<String, Object>> fileList = atchFileMapper.selectSingoFileList(paramMap);
			if (fileList == null || fileList.isEmpty()) {
				return "첨부파일이 존재하지 않습니다. 관리자에게 문의하십시오.";
			}

			int totalCnt = fileList.size();
			int uCnt = 0; // 복원 중인(건너뛴) 파일 수
			boolean isUpdated = false;

			for (HashMap<String, Object> file : fileList) {
				Integer cNo = MapUtils.getInteger(file, "C_NO");
				if (cNo != null) {
					FileSyncMngVO vo = fileSyncMngMapper.selectFileSyncMng2(cNo);

					// 1. 복원 중(1) 복원대상(7) 인 경우 건너뜀
					if (vo != null && (vo.getQueueStt() == 1 || vo.getQueueStt() == 7)) {
						uCnt++;
						continue;
					}

					// 2. 나머지는 상태 업데이트 (업무망 복원 중: 7)
					FileSyncMngDto updateDto = new FileSyncMngDto();
					updateDto.setFileQCNo(cNo);
					updateDto.setQueueStt(7);
					updateDto.setcId(MapUtils.getString(paramMap, "userId"));
					updateDto.setcRelation(1);

					if (vo == null) {
						// 2-1. 데이터가 없으면 insert
						fileSyncMngMapper.insertFileSyncMng(updateDto);
					} else {
						// 2-2. 데이터가 있으면 update
						fileSyncMngMapper.updateFileSyncMng2(updateDto);
					}
					isUpdated = true;
				}
			}

			// 3. 결과 코드 반환
			if (uCnt == totalCnt) {
				return "복원중 입니다 잠시만 기다려 주세요."; 	// 이미 복원요청중
			} else if (uCnt > 0) {
				return "복원중 입니다 잠시만 기다려 주세요."; 	// 일부 복원 중 포함됨 (나머지는 요청 완료)
			} else {
				return "첨부파일을 불러오고 있습니다. 약 5분 후 다시 확인하여 주시기 바랍니다.";		// 복원 대상
			}

		} catch (Exception e) {
			logger.error("복원 프로세스 중 오류 발생: {}", e.getMessage());
			return "문제가 발생하였습니다. 관리자에게 문의하십시요.";
		}
    }

